import React, { useState } from 'react';
import { getCardImageUrl, getCardFallbackImage, getOptimizedCardImageUrl } from '../utils/imageUtils';

const CardDisplay = ({ card, size = 'medium', showStats = true, style = {} }) => {
  const [imageError, setImageError] = useState(false);
  const [imageLoading, setImageLoading] = useState(true);

  const handleImageError = () => {
    setImageError(true);
    setImageLoading(false);
  };

  const handleImageLoad = () => {
    setImageLoading(false);
  };

  // Size configurations
  const sizeConfig = {
    small: { width: 150, height: 210 },
    medium: { width: 200, height: 280 },
    large: { width: 300, height: 420 }
  };

  const { width, height } = sizeConfig[size] || sizeConfig.medium;

  // Get optimized image URL with size parameters
  const imageUrl = imageError 
    ? getCardFallbackImage(card)
    : getOptimizedCardImageUrl(card, { 
        width, 
        height, 
        quality: 'auto',
        format: 'auto'
      });

  if (!card) {
    return (
      <div style={{ 
        width, 
        height, 
        border: '1px solid #ddd', 
        display: 'flex', 
        alignItems: 'center', 
        justifyContent: 'center',
        background: '#f5f5f5',
        ...style 
      }}>
        <span>No Card</span>
      </div>
    );
  }

  return (
    <div style={{ 
      display: 'flex', 
      flexDirection: 'column', 
      alignItems: 'center',
      ...style 
    }}>
      <div style={{ position: 'relative', width, height }}>
        {imageLoading && (
          <div style={{
            position: 'absolute',
            top: 0,
            left: 0,
            width: '100%',
            height: '100%',
            background: '#f0f0f0',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            border: '1px solid #ddd',
            borderRadius: '8px'
          }}>
            <span>Loading...</span>
          </div>
        )}

        <img
          src={imageUrl}
          alt={`${card.character} - ${card.rarity}`}
          onError={handleImageError}
          onLoad={handleImageLoad}
          style={{
            width: '100%',
            height: '100%',
            objectFit: 'cover',
            borderRadius: '8px',
            border: '1px solid #ddd',
            display: imageLoading ? 'none' : 'block'
          }}
        />
      </div>

      {showStats && (
        <div style={{ marginTop: '0.5rem', textAlign: 'center', fontSize: '0.9em' }}>
          <div><strong>{card.character}</strong></div>
          <div style={{ color: '#666' }}>{card.rarity}</div>
          {card.aura !== undefined && (
            <div style={{ marginTop: '0.25rem' }}>
              <span>Aura: {card.aura} | </span>
              <span>Skill: {card.skill} | </span>
              <span>Stamina: {card.stamina}</span>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default CardDisplay;
